mapper.select:
SELECT i.id as inquiryId, i.user_id as userId, u.name as userName, i.category, i.title, i.content, i.file, i.result, i.status, i.reg_date as regDate, i.process_date as processDate FROM INQUIRY i LEFT JOIN USER u ON (i.user_id = u.id) WHERE i.status = #{status}
AND (i.title LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY i.reg_date DESC
